1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_PRICE = 60;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	export function claimOffice(input: any): unknown {
14	  const items = input.steps[0].items;
15	  let basePremium = items.reduce((sum: number, item: any) => {
16	    let itemPremium = BASE_PREMIUMS[item.type];
17	    if (item.cursed) {
18	      itemPremium += itemPremium * 0.5;
19	    }
20	    return sum + itemPremium;
21	  }, 0);
22	
23	  const typeCounts: Record<string, number> = {};
24	  for (const item of items) {
25	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
26	  }
27	  for (const type in typeCounts) {
28	    if (typeCounts[type] === 3) {
29	      basePremium = basePremium - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
30	    }
31	  }
32	
33	  const premium = basePremium + PROCESSING_FEE;
34	  return { results: [{ premium }] };
35	}
